import os
from PIL import Image, ImageDraw, ImageFont, ImageOps

# Source files generated by AI
BRAIN_DIR = r"C:\Users\user\.gemini\antigravity\brain\9d9605af-a205-47db-937a-04dc434d6e05"
GOLD_BASE = os.path.join(BRAIN_DIR, "gold_badge_1772153635176.png")
DIAMOND_BASE = os.path.join(BRAIN_DIR, "diamond_badge_1772153780763.png")
SILVER_BASE = os.path.join(BRAIN_DIR, "silver_badge_1772153795567.png")
BLUE_MEDAL = os.path.join(BRAIN_DIR, "punctual_medal_1772154937459.png")
